module RefModule(
    X   ,
    A_N ,
    B   ,
    C   ,
    D   
);output X   ;
    input  A_N ;
    input  B   ;
    input  C   ;
    input  D   ;

    reg obf_X_reg;

    always @(A_N or B or C or D) begin
        obf_X_reg <= ~(A_N & B & C & D);
    end

    assign X = obf_X_reg;

endmodule
